"use client"

import * as React from "react"

import { EventCardDrawer } from "./event-card-drawer"
import { EventCardPreview } from "./event-card-preview"
import type { DrawerDirection, EventCardProps } from "./types"

function useResolvedDirection(direction: DrawerDirection) {
  const [isDesktop, setIsDesktop] = React.useState(false)

  React.useEffect(() => {
    const mediaQuery = window.matchMedia("(min-width: 768px)")
    const sync = () => setIsDesktop(mediaQuery.matches)
    sync()
    mediaQuery.addEventListener("change", sync)
    return () => mediaQuery.removeEventListener("change", sync)
  }, [])

  return direction === "auto" ? (isDesktop ? "right" : "bottom") : direction
}

export function EventCard({
  title,
  miniDescription,
  ctaText,
  cardCtaText,
  drawerCtaText,
  hideCardCta = false,
  hideDrawerCta = false,
  isActive,
  category,
  image,
  date,
  time,
  isOnline,
  eventLocationLink,
  showLocationTextInMapsTag = true,
  eventLocationText,
  eventMode,
  eventDetailDescription,
  eventTimeline,
  onCtaClick,
  drawerDirection = "auto",
}: EventCardProps) {
  const [open, setOpen] = React.useState(false)
  const resolvedDirection = useResolvedDirection(drawerDirection)
  const resolvedCardCtaText = cardCtaText ?? ctaText
  const resolvedDrawerCtaText = drawerCtaText ?? ctaText

  const handleCtaClick = () => {
    setOpen(true)
  }

  return (
    <>
      <EventCardPreview
        title={title}
        miniDescription={miniDescription}
        ctaText={resolvedCardCtaText}
        hideCardCta={hideCardCta}
        isActive={isActive}
        category={category}
        image={image}
        onCtaClick={handleCtaClick}
      />
      <EventCardDrawer
        title={title}
        ctaText={resolvedDrawerCtaText}
        hideDrawerCta={hideDrawerCta}
        isActive={isActive}
        category={category}
        image={image}
        date={date}
        time={time}
        isOnline={isOnline}
        eventLocationLink={eventLocationLink}
        showLocationTextInMapsTag={showLocationTextInMapsTag}
        eventLocationText={eventLocationText}
        eventMode={eventMode}
        eventDetailDescription={eventDetailDescription}
        eventTimeline={eventTimeline}
        onCtaClick={onCtaClick}
        open={open}
        onOpenChange={setOpen}
        resolvedDirection={resolvedDirection}
      />
    </>
  )
}

export type { EventCardProps, EventTimelineItem, DrawerDirection } from "./types"

import type { EventCardProps } from "./types";
import { CardCtaButton } from "../shared/card-cta-button";

function toCapitalizedWords(value: string) {
  return value.replace(/\b\w/g, (char) => char.toUpperCase());
}

type EventCardPreviewProps = Pick<
  EventCardProps,
  | "title"
  | "miniDescription"
  | "ctaText"
  | "hideCardCta"
  | "isActive"
  | "category"
  | "image"
> & {
  onCtaClick: () => void;
};

export function EventCardPreview({
  title,
  miniDescription,
  ctaText,
  hideCardCta,
  isActive,
  category,
  image,
  onCtaClick,
}: EventCardPreviewProps) {
  const resolvedTitle = toCapitalizedWords(title);
  const resolvedMiniDescription = toCapitalizedWords(miniDescription);
  const resolvedCategory = toCapitalizedWords(category);
  const resolvedCtaText = toCapitalizedWords(ctaText);

  return (
    <div className="font-poppins flex h-full w-full max-w-[300px] flex-col overflow-hidden rounded-[12px] border border-[#E5E7EB] bg-white">
      <img
        src={image}
        alt={resolvedTitle}
        className="h-[84px] w-full rounded-t-[12px] object-cover"
      />

      <div className="flex flex-1 flex-col p-4">
        <div className="mb-3 flex items-center gap-2">
          <span className="rounded-[32px] border border-[#E5E7EB] bg-[#E5E7EB] px-2 py-[2px] text-[12px] font-[500] leading-[16px] text-[#374151]">
            {resolvedCategory}
          </span>
          <span
            className={`rounded-[32px] px-2 py-[2px] text-[12px] font-[500] leading-[16px] ${
              isActive
                ? "bg-[#00B178] text-[#fff]"
                : "bg-[#F3F4F6] text-[#6B7280]"
            }`}
          >
            {isActive ? "Active" : "Inactive"}
          </span>
        </div>
        <h3 className="text-[14px] font-[600] leading-[20px] text-[#111928]">
          {resolvedTitle}
        </h3>
        <p className="mt-[8px] line-clamp-2 text-[12px] font-[400] leading-[16px] text-[#4B5563]">
          {resolvedMiniDescription}
        </p>

        {!hideCardCta ? (
          <div className="mt-auto flex justify-end pt-4">
            <CardCtaButton text={resolvedCtaText} onClick={onCtaClick} />
          </div>
        ) : null}
      </div>
    </div>
  );
}

"use client";

import * as Dialog from "@radix-ui/react-dialog";
import {
  CalendarDots,
  ClockAfternoon,
  GlobeHemisphereWest,
  MapPin,
  X,
} from "@phosphor-icons/react";

import { CardCtaButton } from "../shared/card-cta-button";
import type { DrawerDirection, EventCardProps } from "./types";
import type { ReactNode } from "react";

type EventMetaTagProps = {
  icon: ReactNode;
  value: string;
  href?: string;
  className?: string;
};

function toCapitalizedWords(value: string) {
  return value.replace(/\b\w/g, (char) => char.toUpperCase());
}

function EventMetaTag({
  icon,
  value,
  href,
  className = "",
}: EventMetaTagProps) {
  const resolvedValue = toCapitalizedWords(value);
  const sharedClassName = `flex min-w-0 flex-1 items-center gap-2 rounded-[8px] border border-[#E5E7EB] bg-[#FFF4ED] px-2 py-2 text-[12px] text-[#374151] ${className}`;

  if (href) {
    return (
      <a
        href={href}
        target="_blank"
        rel="noreferrer noopener"
        className={`${sharedClassName} hover:opacity-90`}
      >
        {icon}
        <span className="truncate text-[#374151] underline underline-offset-2">
          {resolvedValue}
        </span>
      </a>
    );
  }

  return (
    <div className={sharedClassName}>
      {icon}
      <span className="truncate">{resolvedValue}</span>
    </div>
  );
}

type EventCardDrawerProps = Pick<
  EventCardProps,
  | "title"
  | "ctaText"
  | "hideDrawerCta"
  | "isActive"
  | "category"
  | "image"
  | "date"
  | "time"
  | "isOnline"
  | "eventLocationLink"
  | "showLocationTextInMapsTag"
  | "eventLocationText"
  | "eventMode"
  | "eventDetailDescription"
  | "eventTimeline"
  | "onCtaClick"
> & {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  resolvedDirection: Exclude<DrawerDirection, "auto">;
};

export function EventCardDrawer({
  title,
  ctaText,
  hideDrawerCta,
  isActive,
  category,
  image,
  date,
  time,
  isOnline,
  eventLocationLink,
  showLocationTextInMapsTag,
  eventLocationText,
  eventMode,
  eventDetailDescription,
  eventTimeline,
  onCtaClick,
  open,
  onOpenChange,
  resolvedDirection,
}: EventCardDrawerProps) {
  const resolvedTitle = toCapitalizedWords(title);
  const resolvedCategory = toCapitalizedWords(category);
  const resolvedEventDetailDescription = toCapitalizedWords(
    eventDetailDescription,
  );
  const resolvedCtaText = toCapitalizedWords(ctaText);
  const mapTagValue =
    showLocationTextInMapsTag && eventLocationText?.trim()
      ? `${eventLocationText.trim()} - View On Maps`
      : "View On Maps";

  return (
    <Dialog.Root open={open} onOpenChange={onOpenChange}>
      <Dialog.Portal>
        <Dialog.Overlay className="fixed inset-0 z-50 bg-black/50 transition-opacity duration-300 ease-out data-[state=closed]:opacity-0 data-[state=open]:opacity-100" />
        <Dialog.Content
          className={`fixed z-50 border bg-white font-poppins shadow-xl outline-none ${
            resolvedDirection === "right"
              ? "right-0 top-0 flex h-svh w-full max-w-[420px] flex-col border-l transition-transform duration-300 ease-out will-change-transform data-[state=closed]:translate-x-full data-[state=open]:translate-x-0"
              : "bottom-0 left-0 flex w-full max-h-[88svh] flex-col rounded-t-2xl border-t transition-transform duration-300 ease-out will-change-transform data-[state=closed]:translate-y-full data-[state=open]:translate-y-0"
          }`}
        >
          <div className="flex items-start justify-between border-b p-4">
            <Dialog.Title className="text-lg font-semibold text-slate-900">
              Event Details
            </Dialog.Title>
            <Dialog.Close className="inline-flex size-8 items-center justify-center rounded-md border text-slate-500 hover:bg-slate-50 hover:text-slate-800">
              <X size={16} />
              <span className="sr-only">Close</span>
            </Dialog.Close>
          </div>

          <div className="min-h-0 flex-1 overflow-y-auto p-4">
            <img
              src={image}
              alt={resolvedTitle}
              className="block max-h-[350px] w-full rounded-[10px] border border-[#E5E7EB] object-fill"
            />

            <div className="mt-3 flex items-center gap-2">
              <span className="rounded-[32px] border border-[#E5E7EB] px-2 py-1 text-[12px] font-[500] leading-[16px] text-[#374151]">
                {resolvedCategory}
              </span>
              <span
                className={`rounded-[32px] px-2 py-1 text-[12px] font-[500] leading-[16px] ${
                  isActive
                    ? "bg-[#ECFDF3] text-[#027A48]"
                    : "bg-[#F3F4F6] text-[#6B7280]"
                }`}
              >
                {isActive ? "Active" : "Inactive"}
              </span>
            </div>

            <h3 className="mt-4 text-[20px] font-[600] leading-[30px] text-[#111928]">
              {resolvedTitle}
            </h3>

            {isOnline ? (
              <div className="mt-4 flex items-stretch justify-between gap-2">
                <EventMetaTag
                  icon={<CalendarDots size={14} color="#EF8833" />}
                  value={date}
                />
                <EventMetaTag
                  icon={<ClockAfternoon size={14} color="#EF8833" />}
                  value={time}
                />
                <EventMetaTag
                  icon={<GlobeHemisphereWest size={14} color="#EF8833" />}
                  value={eventMode}
                />
              </div>
            ) : (
              <div className="mt-4 space-y-2">
                <div className="flex items-stretch justify-between gap-2">
                  <EventMetaTag
                    icon={<CalendarDots size={14} color="#EF8833" />}
                    value={date}
                  />
                  <EventMetaTag
                    icon={<ClockAfternoon size={14} color="#EF8833" />}
                    value={time}
                  />
                </div>
                <EventMetaTag
                  icon={<MapPin size={14} color="#EF8833" />}
                  value={mapTagValue}
                  href={eventLocationLink}
                  className="w-full flex-none"
                />
              </div>
            )}

            <p className="mt-4 text-[14px] leading-[22px] text-[#374151]">
              {resolvedEventDetailDescription}
            </p>

            <div className="mt-6">
              <h4 className="text-[14px] font-[600] leading-[20px] text-[#111928]">
                Event timeline
              </h4>
              <div className="mt-3 space-y-4">
                {eventTimeline.map((item, index) => (
                  <div key={`${item.time}-${index}`} className="relative pl-6">
                    {index < eventTimeline.length - 1 ? (
                      <span className="absolute left-[7px] top-4 h-[calc(100%+12px)] w-px bg-[#D1D5DB]" />
                    ) : null}
                    <span className="absolute left-1 top-1.5 size-[8px] rounded-full bg-[#EF8833]" />
                    <p className="text-[12px] font-[600] leading-[16px] text-[#111928]">
                      {toCapitalizedWords(item.time)}
                    </p>
                    <p className="mt-1 text-[14px] leading-[20px] text-[#374151]">
                      {toCapitalizedWords(item.text)}
                    </p>
                  </div>
                ))}
              </div>
            </div>
          </div>

          {!hideDrawerCta ? (
            <div className="border-t p-4">
              <CardCtaButton
                text={resolvedCtaText}
                onClick={onCtaClick}
                fullWidth
              />
            </div>
          ) : null}
        </Dialog.Content>
      </Dialog.Portal>
    </Dialog.Root>
  );
}

type CardCtaButtonProps = {
  text: string;
  onClick?: () => void;
  theme?: "yellow" | "red";
  fullWidth?: boolean;
  className?: string;
};

const THEME_CLASSES = {
  yellow: "bg-[#EF8833] text-[#fff] hover:bg-[#DC7A2D]",
  red: "bg-[#EF4444] text-white hover:bg-[#DC2626]",
} as const;

export function CardCtaButton({
  text,
  onClick,
  theme = "yellow",
  fullWidth = false,
  className = "",
}: CardCtaButtonProps) {
  return (
    <button
      type="button"
      onClick={onClick}
      className={`inline-flex items-center justify-center rounded-[8px] px-[16px] py-[8px] text-[14px] font-[500] leading-[20px] font-poppins transition-colors ${fullWidth ? "w-full" : ""} ${THEME_CLASSES[theme]} ${className}`.trim()}
    >
      {text}
    </button>
  );
}
